var baseUrl = 'https://{$SMARTZONE_URL}/wsg/api/public/v11_1';
var token   = '{$SMARTZONE_TOKEN}';

function getJson(url) {
    var req = new HttpRequest();
    req.addHeader('Content-Type: application/json;charset=UTF-8');
    var body = req.get(url);
    return {status: req.getStatus(), data: JSON.parse(body)};
}

// Fetch all domains recursively (one call)
var dr = getJson(baseUrl + '/domains?serviceTicket=' + token + '&recursively=true&listSize=1000');
if (dr.status !== 200) throw new Error('Domains failed: ' + dr.status);

// Build domain map {id: {name, parent, zoneCount}}
var domMap = {};
var domList = dr.data.list || [];
for (var i = 0; i < domList.length; i++) {
    var d = domList[i];
    domMap[d.id] = {name: d.name, parent: d.parentDomainId || null, zoneCount: d.zoneCount || 0};
}

// Build hierarchy path: 'Domain :: Sub :: ...' (stops at root = no parent)
function domainPath(id) {
    var parts = [], cur = id, seen = {};
    while (cur && domMap[cur] && domMap[cur].parent && !seen[cur]) {
        seen[cur] = 1;
        parts.unshift(domMap[cur].name);
        cur = domMap[cur].parent;
    }
    return parts.join(' :: ');
}

// Fetch zones for each domain that has zones
var zones = [];
for (var domId in domMap) {
    if (!domMap[domId].zoneCount) continue;
    var zr = getJson(baseUrl + '/rkszones?serviceTicket=' + token + '&domainId=' + domId + '&listSize=1000');
    if (zr.status !== 200) {
        Zabbix.log(4, 'SmartZone: zones for domain ' + domId + ' failed: ' + zr.status);
        continue;
    }
    var dPath = domainPath(domId);
    var zList = zr.data.list || [];
    for (var j = 0; j < zList.length; j++) {
        var z = zList[j];
        zones.push({
            zoneId: z.id,
            zoneName: z.name,
            domainId: domId,
            zonePath: dPath ? dPath + ' :: ' + z.name : z.name
        });
    }
}

return JSON.stringify(zones);

var baseUrl  = 'https://{$SMARTZONE_URL}/wsg/api/public/v11_1';
var token    = '{$SMARTZONE_TOKEN}';
var zoneId   = '{$SMARTZONE_ZONE_ID}';
var listSize = 5;

// Fetch AP list for the configured zone
var listReq = new HttpRequest();
listReq.addHeader('Content-Type: application/json;charset=UTF-8');
var listResp = listReq.get(baseUrl + '/aps?serviceTicket=' + token + '&zoneId=' + zoneId + '&listSize=' + listSize);
if (listReq.getStatus() !== 200) throw new Error('AP list failed: ' + listReq.getStatus());
var aps = JSON.parse(listResp).list || [];

// Enrich each AP with IP from operational summary
for (var i = 0; i < aps.length; i++) {
    var ap = aps[i];
    if (!ap.mac) { ap.ip = null; continue; }
    try {
        var sumReq = new HttpRequest();
        sumReq.addHeader('Content-Type: application/json;charset=UTF-8');
        var sumResp = sumReq.get(baseUrl + '/aps/' + ap.mac + '/operational/summary?serviceTicket=' + token);
        if (sumReq.getStatus() === 200) {
            ap.ip = JSON.parse(sumResp).ip || null;
        } else {
            Zabbix.log(4, 'SmartZone: summary mac=' + ap.mac + ' status=' + sumReq.getStatus());
            ap.ip = null;
        }
    } catch (e) {
        Zabbix.log(3, 'SmartZone: summary error mac=' + ap.mac + ': ' + e.message);
        ap.ip = null;
    }
}

return JSON.stringify(aps);

